// Quota cost reminder: 1,600 units per videos.insert call
// Daily quota: 10,000 units → max 6 uploads/day
// This run will use approximately 1,600 units for long-form
console.log('YouTube upload initiated. Quota cost: ~1,600 units (of 10,000 daily limit)');

const item = $input.first().json;
const processedVideo = item.visual_assets.processed_video;
const youtubeMetadata = item.platform_angles && item.platform_angles.youtube_long
  ? item.platform_angles.youtube_long
  : { title: item.topic_title, description: '' };

// Parse GCS path: gs://bucket-name/path/to/file.mp4
let gcsBucket = '';
let gcsObject = '';
if (processedVideo.startsWith('gs://')) {
  const withoutProtocol = processedVideo.replace('gs://', '');
  const slashIdx = withoutProtocol.indexOf('/');
  gcsBucket = withoutProtocol.substring(0, slashIdx);
  gcsObject = withoutProtocol.substring(slashIdx + 1);
} else {
  // Already a signed URL or HTTPS path
  gcsBucket = '';
  gcsObject = '';
}

// CTA booking link per brand voice guidelines
const bookingCTA = 'Book a free 15-min discovery call: https://calendar.app.google/psycao3CrXjGnmk48';
const fullDescription = youtubeMetadata.description
  ? youtubeMetadata.description + '\n\n' + bookingCTA
  : bookingCTA;

return [{
  json: {
    ...item,
    longform: {
      title: youtubeMetadata.title || item.topic_title,
      description: fullDescription,
      categoryId: '27',
      privacyStatus: 'private',
      gcs_path: processedVideo,
      gcs_bucket: gcsBucket,
      gcs_object: gcsObject
    },
    quota_estimate: '~1,600 units for long-form upload (of 10,000 daily limit)'
  }
}];

// Quota cost reminder: 1,600 units per videos.insert call
// Total for this run (long-form + Short): ~3,200 units (of 10,000 daily limit)
console.log('YouTube Shorts upload initiated. Total quota this run: ~3,200 units (of 10,000 daily limit)');

const item = $('Supabase Trigger (approved status)').item.json;
const clips = item.visual_assets.clips || [];

// Sort clips by strength_score descending, pick the best one
const sortedClips = [...clips].sort((a, b) => {
  const scoreA = a.strength_score || 0;
  const scoreB = b.strength_score || 0;
  return scoreB - scoreA;
});

const bestClip = sortedClips[0];

if (!bestClip || !bestClip.path) {
  throw new Error('No valid clip found with a GCS path — cannot upload Short');
}

// Parse GCS path for the clip
let gcsBucket = '';
let gcsObject = '';
const clipPath = bestClip.path;
if (clipPath.startsWith('gs://')) {
  const withoutProtocol = clipPath.replace('gs://', '');
  const slashIdx = withoutProtocol.indexOf('/');
  gcsBucket = withoutProtocol.substring(0, slashIdx);
  gcsObject = withoutProtocol.substring(slashIdx + 1);
}

// CTA booking link per brand voice guidelines
const bookingCTA = 'Book a free 15-min discovery call: https://calendar.app.google/psycao3CrXjGnmk48';

// Build Shorts description — #Shorts tag is required for YouTube to auto-classify
const shortsBaseDescription = item.platform_angles && item.platform_angles.youtube_short
  ? item.platform_angles.youtube_short
  : item.topic_title;
const shortsDescription = shortsBaseDescription + '\n\n#Shorts\n\n' + bookingCTA;

// Shorts title: must be under 100 chars total
const rawTitle = item.topic_title + ' #Shorts';
const shortsTitle = rawTitle.length <= 100 ? rawTitle : rawTitle.substring(0, 97) + '...';

return [{
  json: {
    ...item,
    short: {
      title: shortsTitle,
      description: shortsDescription,
      categoryId: '27',
      privacyStatus: 'private',
      gcs_path: clipPath,
      gcs_bucket: gcsBucket,
      gcs_object: gcsObject,
      strength_score: bestClip.strength_score || 0
    }
  }
}];
